#include<bits/stdc++.h>
#define MAXN 1000010
using namespace std;
struct Node {
    int left,right;
} t[MAXN];
void pre_order(int x ){
	cout<<x<<' ';
	if(t[x].left)pre_order(t[x].left);
	if(t[x].right)pre_order(t[x].right);
}
void in_order(int x){
	if(t[x].left)in_order(t[x].left);
    cout<<x<<' ';
	if(t[x].right)in_order(t[x].right);
}
void post_order(int x){
    if(t[x].left)post_order(t[x].left);
    if(t[x].right)post_order(t[x].right);
    cout<<x<<' ';
}
int main(void){
    int n;
    cin>>n;
    for(int i = 1; i <= n; i++)cin>>t[i].left>>t[i].right;
    pre_order(1);
    cout<<endl;
    in_order(1);
    cout<<endl;
    post_order(1);
    cout<<endl;
    return false;
}
